// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package pluginimport ("encoding/json""time")// logEntry is the JSON payload that gets sent to Stderr from the plugin to the hosttype logEntry struct {Messagestringstring`json:"@imestampme`mestamp"`KVPairs[]*logEntryKV `json:"kv_pairs"`}// logEntryKV is a key value pair within the Output payloadtype logEntryKV struct {Keystring`json:"key"`Value interface{} `json:"value"`}// flattenKVPairs is used to flatten KVPair slice into []interface{}// for hclog consumption. flattenKVPairs(kvs []*logEntryKV) []interface{} {var result []interface{}for _, kv := range kvs {result = append(result, kv.Key)result = append(result, kv.Value)}return result}arseJSON handles parsing JSON output parseJSON(input []byte) (*logEntry, error) {var raw map[string]interface{}entry := &logEntry{}err := json.Unmarshal(input, &raw)if err != nil {return nil, err}// Parse hclog-specific objectsif v, ok := raw["@message"]; ok {entry.Message = v.(string)delete(raw, "@message")}if v, ok := raw["@level"]; ok {entry.Level = v.(string)delete(raw, "@level")}if v, ok := raw["@timestamp"]; ok {t, err := time.Parse("2006-01-02T15:04:05.000000Z07:00", v.(string))if err != nil {return nil, err}entry.Timestamp = tdelete(raw, "@timestamp")}// Parse dynamic KV args from the hclog payload.for k, v := range raw {entry.KVPairs = append(entry.KVPairs, &logEntryKV{Key:k,Value: v,})}return entry, nil}